import React from 'react';
import { Link } from 'react-router-dom';
import { AppstoreOutlined, MailOutlined, SettingOutlined } from '@ant-design/icons';
import type { MenuProps } from 'antd';
import { Menu } from 'antd';

type MenuItem = Required<MenuProps>['items'][number];

function getItem(
  label: React.ReactNode,
  key?: React.Key | null,
  icon?: React.ReactNode,
  children?: MenuItem[],
  type?: 'group',
  linkTo?: string, // Add linkTo property for the link
): MenuItem {
  return {
    key,
    icon,
    children,
    label,
    type,
    linkTo,
  } as MenuItem;
}

const items: MenuItem[] = [
  getItem('Navigation One', 'sub1', <MailOutlined />, [
    getItem('Item 1', null, null, [getItem('Option 1', '1', undefined, undefined, undefined, '/option1')], 'group'),
    getItem('Item 2', null, null, [getItem('Option 2', '2', undefined, undefined, undefined, '/option2')], 'group'),
  ]),

  getItem('Navigation Two', 'sub2', <AppstoreOutlined />, [
    getItem('Option 5', '5', undefined, undefined, undefined, '/option5'),
    getItem('Option 6', '6', undefined, undefined, undefined, '/option6'),
    getItem('Submenu', 'sub3', null, [getItem('Option 7', '7', undefined, undefined, undefined, '/option7')]),
  ]),

  getItem('Navigation Three', 'sub4', <SettingOutlined />, [
    getItem('Option 9', '9', undefined, undefined, undefined, '/option9'),
    getItem('Option 10', '10', undefined, undefined, undefined, '/option10'),
    getItem('Option 11', '11', undefined, undefined, undefined, '/option11'),
    getItem('Option 12', '12', undefined, undefined, undefined, '/option12'),
  ]),
];

const MenuItems = () => (
  <Menu className='MenuItems' mode="vertical" items={items.map(item => (
    item.linkTo ? (
      <Link key={item.key} to={item.linkTo}>
        {item.label}
      </Link>
    ) : (
      <span key={item.key}>
        {item.label}
      </span>
    )
  ))} />
);

export default MenuItems;
